import json
from datetime import datetime
from pathlib import Path
from typing import Dict, List, Optional

class Deal:
    """Simple deal object for pipeline"""
    def __init__(self, deal_id: str, company: str, value: float, stage: str):
        self.deal_id = deal_id
        self.company = company
        self.value = value
        self.stage = stage  # "lead" | "qualified" | "proposal" | "won" | "lost"
        self.created_at = datetime.now().isoformat()
        self.updated_at = datetime.now().isoformat()
        self.metadata = {}

    def to_dict(self) -> Dict:
        return {
            "deal_id": self.deal_id,
            "company": self.company,
            "value": self.value,
            "stage": self.stage,
            "created_at": self.created_at,
            "updated_at": self.updated_at,
            "metadata": self.metadata
        }

    @classmethod
    def from_dict(cls, data: Dict):
        deal = cls(data["deal_id"], data["company"], data["value"], data["stage"])
        deal.created_at = data.get("created_at", deal.created_at)
        deal.updated_at = data.get("updated_at", deal.updated_at)
        deal.metadata = data.get("metadata", {})
        return deal


class CRMDataModel:
    """Store/retrieve deals from memory"""
    def __init__(self, memory_path: str = "C:/TAD/memory"):
        self.memory = Path(memory_path)
        self.deals_file = self.memory / "crm_deals.json"
        self._ensure_file()

    def _ensure_file(self):
        if not self.deals_file.exists():
            self.deals_file.write_text(json.dumps({"deals": []}, indent=2))

    def add_deal(self, deal: Deal) -> bool:
        try:
            data = json.loads(self.deals_file.read_text())
            data["deals"].append(deal.to_dict())
            self.deals_file.write_text(json.dumps(data, indent=2))
            return True
        except Exception as e:
            print(f"Error adding deal: {e}")
            return False

    def get_all_deals(self) -> List[Deal]:
        try:
            data = json.loads(self.deals_file.read_text())
            return [Deal.from_dict(d) for d in data.get("deals", [])]
        except:
            return []

    def get_deals_by_stage(self, stage: str) -> List[Deal]:
        return [d for d in self.get_all_deals() if d.stage == stage]

    def update_deal(self, deal_id: str, updates: Dict) -> bool:
        try:
            data = json.loads(self.deals_file.read_text())
            for deal in data["deals"]:
                if deal["deal_id"] == deal_id:
                    deal.update(updates)
                    deal["updated_at"] = datetime.now().isoformat()
            self.deals_file.write_text(json.dumps(data, indent=2))
            return True
        except:
            return False


